/// Carga un archivo DICOM y retorna sus metadatos
/// 
/// # Arguments
/// * `file_path` - Ruta al archivo DICOM
#[tauri::command]
pub fn load_dicom_file(file_path: String) -> Result<DicomImageInfo, String> {
    let path = Path::new(&file_path);
    
    if !path.exists() {
        return Err("El archivo no existe".to_string());
    }
    
    let obj = open_file(path).map_err(|e| format!("Error al abrir DICOM: {}", e))?;
    let metadata = extract_metadata(&obj);
    let width = metadata.image_columns.unwrap_or(0) as u32;
    let height = metadata.image_rows.unwrap_or(0) as u32;
    let has_pixel_data = obj.element(tags::PIXEL_DATA).is_ok();
    
    Ok(DicomImageInfo {
        file_path,
        metadata,
        width,
        height,
        has_pixel_data,
    })
}

