/// Extrae metadatos de un objeto DICOM
fn extract_metadata(obj: &DefaultDicomObject) -> DicomMetadata {
    DicomMetadata {
        patient_name: get_string_value(obj, tags::PATIENT_NAME),
        patient_id: get_string_value(obj, tags::PATIENT_ID),
        patient_birth_date: get_string_value(obj, tags::PATIENT_BIRTH_DATE),
        patient_sex: get_string_value(obj, tags::PATIENT_SEX),
        study_date: get_string_value(obj, tags::STUDY_DATE),
        study_description: get_string_value(obj, tags::STUDY_DESCRIPTION),
        series_description: get_string_value(obj, tags::SERIES_DESCRIPTION),
        modality: get_string_value(obj, tags::MODALITY),
        manufacturer: get_string_value(obj, tags::MANUFACTURER),
        institution_name: get_string_value(obj, tags::INSTITUTION_NAME),
        referring_physician: get_string_value(obj, tags::REFERRING_PHYSICIAN_NAME),
        accession_number: get_string_value(obj, tags::ACCESSION_NUMBER),
        study_id: get_string_value(obj, tags::STUDY_ID),
        series_number: get_string_value(obj, tags::SERIES_NUMBER),
        instance_number: get_string_value(obj, tags::INSTANCE_NUMBER),
        image_rows: get_u16_value(obj, tags::ROWS),
        image_columns: get_u16_value(obj, tags::COLUMNS),
        bits_allocated: get_u16_value(obj, tags::BITS_ALLOCATED),
        bits_stored: get_u16_value(obj, tags::BITS_STORED),
        pixel_spacing: get_f32_pair(obj, tags::PIXEL_SPACING),
        slice_thickness: get_f32_value(obj, tags::SLICE_THICKNESS),
        window_center: get_f32_value(obj, tags::WINDOW_CENTER),
        window_width: get_f32_value(obj, tags::WINDOW_WIDTH),
    }
}

/// Obtiene un valor string de un tag DICOM
fn get_string_value(obj: &DefaultDicomObject, tag: dicom::core::Tag) -> Option<String> {
    obj.element(tag)
        .ok()
        .and_then(|e| e.to_str().ok())
        .map(|s| s.trim().to_string())
}

/// Obtiene un valor u16 de un tag DICOM
fn get_u16_value(obj: &DefaultDicomObject, tag: dicom::core::Tag) -> Option<u16> {
    obj.element(tag)
        .ok()
        .and_then(|e| e.to_int::<u16>().ok())
}

/// Obtiene un valor f32 de un tag DICOM (toma el primer valor si es múltiple)
fn get_f32_value(obj: &DefaultDicomObject, tag: dicom::core::Tag) -> Option<f32> {
    obj.element(tag)
        .ok()
        .and_then(|e| e.to_str().ok())
        .and_then(|s| s.split('\\').next().map(|v| v.trim().to_string()))
        .and_then(|v| v.parse::<f32>().ok())
}

/// Obtiene un par de valores f32 (pixel spacing) de un tag DICOM
fn get_f32_pair(obj: &DefaultDicomObject, tag: dicom::core::Tag) -> Option<[f32; 2]> {
    let raw = obj.element(tag).ok().and_then(|e| e.to_str().ok())?;
    let values: Vec<f32> = raw
        .split('\\')
        .filter_map(|v| v.trim().parse::<f32>().ok())
        .collect();
    
    if values.len() >= 2 {
        Some([values[0], values[1]])
    } else {
        None
    }
}

/// Tipos de modalidad DICOM comunes en odontología
#[derive(Debug, Serialize, Deserialize)]
pub enum DentalModality {
    /// Radiografía intraoral
    IO,
    /// Radiografía panorámica
    PX,
    /// Tomografía computarizada Cone Beam
    CT,
    /// Fotografía digital
    XC,
    /// Otro
    Other(String),
}

impl From<&str> for DentalModality {
    fn from(s: &str) -> Self {
        match s.to_uppercase().as_str() {
            "IO" => DentalModality::IO,
            "PX" => DentalModality::PX,
            "CT" => DentalModality::CT,
            "XC" => DentalModality::XC,
            other => DentalModality::Other(other.to_string()),
        }
    }
}

