/// Subir archivo DICOM y guardarlo asociado a un paciente
/// Generated by Copilot
#[tauri::command]
pub async fn upload_dicom_file(
    patient_id: String,
    source_path: String,
    description: Option<String>
) -> Result<DicomUploadResult, String> {
    log::info!("IPC: upload_dicom_file patient={} source={}", patient_id, source_path);
    
    let source = Path::new(&source_path);
    if !source.exists() {
        return Err("Archivo fuente no encontrado".to_string());
    }
    
    // Validar que es un archivo DICOM válido
    let obj = open_file(source).map_err(|e| format!("No es un archivo DICOM válido: {}", e))?;
    let metadata = extract_metadata(&obj);
    
    // Obtener directorio de documentos de la app
    let app_docs = dirs::document_dir()
        .unwrap_or_else(|| std::path::PathBuf::from("."))
        .join("Tlanti4Dental")
        .join("dicom")
        .join(&patient_id);
    
    std::fs::create_dir_all(&app_docs)
        .map_err(|e| format!("Error creando directorio: {}", e))?;
    
    // Generar nombre único para el archivo
    let doc_id = uuid::Uuid::new_v4().to_string();
    let timestamp = chrono::Utc::now().format("%Y%m%d_%H%M%S");
    let extension = source.extension()
        .and_then(|e| e.to_str())
        .unwrap_or("dcm");
    
    let dest_filename = format!("{}_{}.{}", doc_id, timestamp, extension);
    let dest_path = app_docs.join(&dest_filename);
    
    // Copiar archivo
    std::fs::copy(source, &dest_path)
        .map_err(|e| format!("Error copiando archivo: {}", e))?;
    
    // Guardar en base de datos con sqlx
    let pool = tlanti_db::get_pool().await?;
    let now = chrono::Utc::now().to_rfc3339();
    let modality = metadata.modality.clone().unwrap_or_else(|| "Unknown".to_string());
    let file_size = std::fs::metadata(&dest_path).map(|m| m.len()).unwrap_or(0) as i64;
    let desc = description.clone().unwrap_or_else(|| metadata.study_description.clone().unwrap_or_default());
    let path_str = dest_path.to_string_lossy().to_string();
    
    sqlx::query(
        "INSERT INTO documents (id, patient_id, type, category, name, description, file_path, file_type, file_size, created_at, updated_at)
         VALUES (?, ?, 'dicom', ?, ?, ?, ?, 'application/dicom', ?, ?, ?)"
    )
    .bind(&doc_id)
    .bind(&patient_id)
    .bind(&modality)
    .bind(&dest_filename)
    .bind(&desc)
    .bind(&path_str)
    .bind(file_size)
    .bind(&now)
    .bind(&now)
    .execute(&pool)
    .await
    .map_err(|e| format!("Error guardando en DB: {}", e))?;
    
    log::info!("DICOM guardado: {} -> {:?}", doc_id, dest_path);
    
    Ok(DicomUploadResult {
        document_id: doc_id,
        file_path: dest_path.to_string_lossy().to_string(),
        metadata,
    })
}

/// Listar archivos DICOM de un paciente
/// Generated by Copilot
#[tauri::command]
pub async fn list_patient_dicom_files(patient_id: String) -> Result<Vec<DicomImageInfo>, String> {
    log::info!("IPC: list_patient_dicom_files patient={}", patient_id);
    
    let pool = tlanti_db::get_pool().await?;
    
    let rows: Vec<(String, String)> = sqlx::query_as(
        "SELECT id, file_path FROM documents WHERE patient_id = ? AND type = 'dicom' ORDER BY created_at DESC"
    )
    .bind(&patient_id)
    .fetch_all(&pool)
    .await
    .unwrap_or_default();
    
    let mut results = Vec::new();
    for (doc_id, file_path) in rows {
        if let Ok(info) = load_dicom_file(file_path.clone()) {
            results.push(DicomImageInfo {
                file_path: doc_id,  // Usar doc_id como referencia
                ..info
            });
        }
    }
    
    Ok(results)
}

/// Eliminar archivo DICOM
/// Generated by Copilot
#[tauri::command]
pub async fn delete_dicom_file(document_id: String) -> Result<bool, String> {
    log::info!("IPC: delete_dicom_file id={}", document_id);
    
    let pool = tlanti_db::get_pool().await?;
    
    // Obtener ruta del archivo
    let file_path: Option<String> = sqlx::query_scalar(
        "SELECT file_path FROM documents WHERE id = ? AND type = 'dicom'"
    )
    .bind(&document_id)
    .fetch_optional(&pool)
    .await
    .ok()
    .flatten();
    
    // Eliminar archivo físico
    if let Some(path) = file_path {
        let _ = std::fs::remove_file(&path);
    }
    
    // Eliminar de la base de datos
    sqlx::query("DELETE FROM documents WHERE id = ?")
        .bind(&document_id)
        .execute(&pool)
        .await
        .map_err(|e| e.to_string())?;
    
    Ok(true)
}

